const express = require('express');
const app = express();
const logger = require('morgan');

app.use(logger('combined'));

app.get('/log', (req, res) => {
  const actionDescription = req.query.action;
  
  if (!actionDescription) {
    return res.status(400).send({ error: 'Action description is required' });
  }
  
  try {
    const logMessage = `User performed action: ${actionDescription} at ${new Date().toISOString()}`;
    console.log(logMessage);
    
    res.send({ message: 'Log recorded successfully' });
  } catch (error) {
    console.error(error);
    return res.status(500).send({ error: 'Failed to record log' });
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});